### Describe the solution you'd like

```js
function headerAssign(source = {}, target = {}) {
  const keys = Object.keys(target)
  const len = keys.length
  const result = Object.assign(Object.create(null), source)

  for (let i = 0; i < len; i += 1) {
    const item = keys[i]
    const cfg = { name: item, type: '+' }
    if (/^[+\-?]/.test(item)) {
      cfg.type = item[0]
      cfg.name = item.slice(1)
    }
    const { type, name } = cfg
    switch (type) {
      case '-':
        Reflect.deleteProperty(result, name)
        break
      case '?':
        result[name] = toString(result[name]) || toString(target[item])
        break
      case '+':
        result[name] = target[name]
        break
    }
  }
  return result
}

// for example
headerAssign({ foo: 'foo', bar: 'bar' }, { '-foo': '' }) // => { bar: 'bar'}
headerAssign({ foo: 'foo' }, { '?foo': 'foo2' }) // => { foo: 'foo'}
headerAssign({ foo: '' }, { '?foo': 'foo2' }) // => { foo: 'foo2' }
```
in `axios`， we can use Symbol like it: 

```js
axios.get('url', {}, { headers: {
  '-foo': '',
  '?bar': 'bar'
}})
