### Describe the bug

Currently, I am using AxiosHeaders instance.clear() to delete all the fields of the current headers, which does not work. So I try to dive into the source code, and found code like this:

```js
class AxiosHeaders {
// ...
  clear() {
    return Object.keys(this).forEach(this.delete.bind(this));
  }

  delete(header, matcher) {
    const self = this;
    let deleted = false;

    function deleteHeader(_header) {
      _header = normalizeHeader(_header);

      if (_header) {
        const key = utils.findKey(self, _header);

        if (key && (!matcher || matchHeaderValue(self, self[key], key, matcher))) {
          delete self[key];

          deleted = true;
        }
      }
    }

    if (utils.isArray(header)) {
      header.forEach(deleteHeader);
    } else {
      deleteHeader(header);
    }

    return deleted;
  }
}
```

The problem here seems like `Array.forEach(this.delete.bind(this))` has passed an implicit index to `delete` methods, which let it hit the `matchHeaderValue()` branch.

Personally, I do not think this is designed intentionally.

At last, appreciate the great work of the axios.


