  url: 'https://meuitinerario.com.br',
  insecureHTTPParser: true, // Should allow invalid header characters
  proxy: {
    host: 'brd.superproxy.io',
    port: 33335,
    protocol: 'http',
    auth: {
      username: '***',
      password: '***'
    }
  }
};

const response = await axios(config);
```

Expect status code 200, returns 502

