    at forEach (/Users/sophia/Code/checkout-core/node_modules/.pnpm/axios@1.8.2/node_modules/axios/dist/node/axios.cjs:297:10)
    at visit (/Users/sophia/Code/checkout-core/node_modules/.pnpm/axios@1.8.2/node_modules/axios/dist/node/axios.cjs:660:9)
    at Object.toJSONObject (/Users/sophia/Code/checkout-core/node_modules/.pnpm/axios@1.8.2/node_modules/axios/dist/node/axios.cjs:674:10)
    at CanceledError.toJSON (/Users/sophia/Code/checkout-core/node_modules/.pnpm/axios@1.8.2/node_modules/axios/dist/node/axios.cjs:816:23)
    at JSON.stringify (<anonymous>)
    at /Users/sophia/Code/checkout-core/packages/utils/src/repro.js:13:22
```


### To Reproduce

```javascript
const axios = require('axios');

axios.interceptors.request.use((config) => {
  if (typeof config.timeout === 'number' && config.timeout > 0) {
    config.cancelToken = new axios.CancelToken((cancel) => {
      setTimeout(() => cancel('Request timed out', config), config.timeout);
    });
  }
  return config;
});

axios.get('http://10.255.255.1', { timeout: 1 }).catch((error) => {
  console.error(JSON.stringify(error));
});
```

### Expected behavior

Calling `JSON.stringify` on the `CanceledError` should not overflow the stack.

It's possible to work around this problem by either not passing `config` to the `cancel` function at all, or by stripping the `cancelToken` from `config`. e.g.:

```
if (typeof config.timeout === 'number' && config.timeout > 0) {
  config.cancelToken = new axios.CancelToken((cancel) => {
    setTimeout(() => {
      const { cancelToken, ...rest } = config;
      cancel('Request timed out', rest);
    }, config.timeout);
  });
}
```

But this isn't ideal as we want to be able to see that the `cancelToken` was actually present when we dig through logs later on.

The root problem seems to be that `AxiosError#toJSON` uses [`toJSONObject`](https://github.com/axios/axios/blob/a9f7689b0c4b6d68c7f587c3aa376860da509d94/lib/utils.js#L616) under the hood, which doesn't handle cyclic references. In this case the cycle comes from `error -> error.config -> config.cancelToken -> cancelToken.reason -> reason.config -> config.cancelToken -> ...`

