instance.interceptors.request.use(
  async config => {
    if (!config) {
      console.error('Request interceptor received empty config');
      return Promise.reject(new Error('Empty request config'));
    }

    // Ensure method exists and normalize it
    if (!config.method) {
      config.method = config.data ? 'post' : 'get';
    }
    if (typeof config.method === 'string') {
      config.method = config.method.toLowerCase();
    } else {
      console.error('Invalid method in request interceptor:', config.method);
      return Promise.reject(new Error('Invalid HTTP method'));
    }

    // Mutate headers in place
    if (!config.headers) {
      config.headers = {};
    }

    // Copy common and method-specific headers if present (flatten them)
    if (config.headers.common) {
      Object.assign(config.headers, config.headers.common);
      delete config.headers.common;
    }
    if (config.headers[config.method]) {
      Object.assign(config.headers, config.headers[config.method]);
      delete config.headers[config.method];
    }

    // Add/override required headers
    config.headers['Content-Type'] = 'application/json';
    config.headers['phone-app'] = 1;

    const token = store.getState().reducer.accessToken;
    if (token) {
      config.headers.Authorization = 'Bearer ' + token;
    }

    // Add offline retry listener once
    if (!isListenerAdded) {
      NetInfo.addEventListener(state => {
        if (state.isConnected && queuedRequests.length > 0) {
          console.log('Back online → retrying queued requests');
          const requestsToRetry = [...queuedRequests];
          queuedRequests.length = 0;

          requestsToRetry.forEach(({config, resolve, reject}, index) => {
            if (!config) {
              console.error(`Retry #${index} skipped: missing config`);
              reject && reject(new Error('Retry skipped: missing config'));
              return;
            }

            if (!config.method) {
              config.method = config.data ? 'post' : 'get';
            }
            if (typeof config.method === 'string') {
              config.method = config.method.toLowerCase();
            } else {
              console.error(
                `Retry #${index} skipped: invalid method`,
                config.method,
              );
              reject && reject(new Error('Retry skipped: invalid method'));
              return;
            }

            console.log(
