            instance(config)
              .then(response => {
                console.log(`Retry #${index} success for url: ${config.url}`);
                resolve && resolve(response);
              })
              .catch(error => {
                console.error(
                  `Retry #${index} failed for url: ${config.url}`,
                  error,
                );
                reject && reject(error);
              });
          });
        }
      });
      isListenerAdded = true;
    }

    // Offline queuing: push the actual config object as-is
    const state = await NetInfo.fetch();
    if (!state.isConnected) {
      console.log('Offline → queuing request:', config.url);

      return new Promise((resolve, reject) => {
        queuedRequests.push({config, resolve, reject});
      });
    }

    // Token refresh logic
    const now = new Date();
    const refresh_time = store.getState().reducer.refreshTime;
    if (refresh_time && now.getTime() > refresh_time) {
      if (!config.data?.extra_param) {
        store.dispatch(
